import json
import re
from collections import Counter

REPLACE_NONE = "None"

def task_func(json_str):
    try:
        data = json.loads(json_str)
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON string")

    email_pattern = re.compile(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b')

    def replace_emails(obj):
        if isinstance(obj, dict):
            return {k: replace_emails(v) for k, v in obj.items()}
        elif isinstance(obj, list):
            return [replace_emails(item) for item in obj]
        elif isinstance(obj, str):
            return email_pattern.sub(REPLACE_NONE, obj)
        else:
            return obj

    data = replace_emails(data)

    data = {k: v for k, v in data.items() if v is not None}

    value_counts = Counter(v for v in data.values())

    return {
        "data": data,
        "value_counts": value_counts
    }
