def task_func(pattern, log_dir='/var/log/'):
    try:
        files = os.listdir(log_dir)
    except OSError:
        return None

    matching_files = []
    for file in files:
        file_path = os.path.join(log_dir, file)
        if os.path.isfile(file_path) and re.match(pattern, file):
