    for char in s:
        if char != first_char:
            return False
    return True

def rotate_right(lst, n):
    if not lst:
        return lst
    n = n % len(lst)
    return lst[-n:] + lst[:-n]

def has_none(tup):
    for element in tup:
        if element is None:
            return True
    return False

def sector_area(radius, angle):
    if angle > 360:
        return None
    return (angle / 360) * 3.141592653589793 * radius ** 2

def add_tuple_to_list(lst, tpl):
    for item in tpl:
        lst.append(item)
    return lst

def count_reverse_pairs(lst):
    seen = set()
    count = 0
    for s in lst:
        rev = s[::-1]
        if rev in seen:
            count += 1
        seen.add(s)
    return count

def count_digits(s):
    count = 0
    for char in s:
        if char.isdigit():
            count += 1
    return count

def consecutive_pairs(lst):
    if len(lst) < 2:
        return []
    return [(lst[i], lst[i+1]) for i in range(len(lst) - 1)]

def count_pairs_with_sum(numbers, target_sum):
    count = 0
    n = len(numbers)
    for i in range(n):
        for j in range(i + 1, n):
            if numbers[i] + numbers[j] == target_sum:
                count += 1
    return count

def sum_of_fourth_powers_of_odd(n):
    total = 0
    for i in range(n):
        odd_number = 2 * i + 1
        total += odd_number ** 4
    return total

def is_balanced(expression):
    stack = []
    pairs = {')': '(', '}': '{', ']': '['}
    for char in expression:
        if char in '({[':
            stack.append(char)
        elif char in ')}]':
            if not stack or stack.pop() != pairs[char]:
                return False
    return len(stack) == 0

def remove_k_length_words(s, k):
    words = s.split()
    filtered_words = [word for word in words if len(word) != k]
    return ' '.join(filtered_words)

def check_odd_indices_odd(lst):
    for i in range(1, len(lst), 2):
        if lst[i] % 2 == 0:
            return False
    return True

from itertools import combinations

def find_combinations_of_sum(tuple_list):
    result = []
    for r in range(1, len(tuple_list) + 1):
        for combo in combinations(tuple_list, r):
            total = sum(sum(t) for t in combo)
            result.append((combo, total))
    return result

def rgb_to_hsv(r, g, b):
    r, g, b = r/255.0, g/255.0, b/255.0
    mx = max(r, g, b)
    mn = min(r, g, b)
    df = mx - mn
    if mx == mn:
        h = 0
    elif mx == r:
        h = (60 * ((g - b) / df) + 360) % 360
    elif mx == g:
        h = (60 * ((b - r) / df) + 120) % 360
    else:
        h = (60 * ((r - g) / df) + 240) % 360
    s = 0 if mx == 0 else (df / mx)
    v = mx
    return h, s, v

def check_even_indices_even(lst):
    for i in range(0, len(lst), 2):
        if lst[i] % 2 != 0:
            return False
    return True

def find_last_position(arr, target):
    left, right = 0, len(arr) - 1
    result = -1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            result = mid
            left = mid + 1
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return result

def sum_odd_numbers(l, r):
