    else:
        return 0

def count_rotations(arr):
    left, right = 0, len(arr) - 1
    while left <= right:
        if arr[left] <= arr[right]:
            return left
        mid = (left + right) // 2
        if arr[mid] > arr[right]:
            left = mid + 1
        else:
            right = mid - 1
    return left

def is_product_even(numbers):
    if not numbers:
