        insertion_pos = bisect.bisect_left(numbers, random.randint(0, total))
        return (numbers, insertion_pos)

    while True:
        splits = [0] + sorted(random.sample(range(1, total), n - 1)) + [total]
        numbers = array('i', [splits[i+1] - splits[i] for i in range(n)])
        if sum(numbers) == total:
            break

    numbers.sort()
    new_number = random.randint(0, total)
    insertion_pos = bisect.bisect_left(numbers, new_number)

    return (numbers, insertion_pos)
```

